-- permission-admin PostgreSQL schema 基线。
--
-- 迁移原则：
-- 1. 只建立权限中心自己的 8 张持久化表，不把暂存于旧 MySQL 初始化脚本中的 agent_memory_* 表迁入本 schema；
-- 2. 主键使用 GENERATED BY DEFAULT AS IDENTITY，既支持 MyBatis-Plus 自动回填，也支持后续存量迁移显式保留旧 ID；
-- 3. Java LocalDateTime 对应 TIMESTAMP WITHOUT TIME ZONE，避免迁移期间发生隐式时区换算；
-- 4. Boolean 字段使用 PostgreSQL BOOLEAN，替代 MySQL TINYINT(1)，让权限开关语义更清晰；
-- 5. outbox payload_json 暂时保留 TEXT，因为 Java 实体字段是 String；未来引入 JSONB 时应同步 TypeHandler 和迁移脚本；
-- 6. DDL 只负责新安装空库基线，已有 MySQL 历史数据通过后续导出、导入、对账和 sequence 校正脚本迁移。

SET search_path TO permission_admin, public;

CREATE TABLE permission_role (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    role_code VARCHAR(64) NOT NULL,
    role_name VARCHAR(128) NOT NULL,
    description VARCHAR(1000),
    system_role BOOLEAN NOT NULL DEFAULT FALSE,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    created_by BIGINT NOT NULL DEFAULT 0,
    updated_by BIGINT,
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_role_tenant_code UNIQUE (tenant_id, role_code),
    CONSTRAINT ck_permission_role_tenant_non_negative CHECK (tenant_id >= 0)
);
COMMENT ON TABLE permission_role IS '平台角色表，保存普通用户、项目负责人、运营、审计、租户管理员、平台管理员和服务账号等角色定义';
COMMENT ON COLUMN permission_role.tenant_id IS '租户 ID，0 表示平台全局默认角色；非 0 表示租户级角色覆盖';
COMMENT ON COLUMN permission_role.role_code IS '稳定角色编码，是菜单绑定、路由策略和数据范围策略的关联键';
COMMENT ON COLUMN permission_role.system_role IS '是否系统内置角色；内置角色不建议普通管理员删除';
COMMENT ON COLUMN permission_role.enabled IS '是否启用；禁用后不应继续参与权限判定';
CREATE INDEX idx_permission_role_enabled ON permission_role (tenant_id, enabled);

CREATE TABLE permission_menu (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    menu_code VARCHAR(128) NOT NULL,
    parent_code VARCHAR(128),
    menu_name VARCHAR(128) NOT NULL,
    path VARCHAR(256) NOT NULL,
    icon VARCHAR(128),
    sort_order INTEGER NOT NULL DEFAULT 100,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    description VARCHAR(1000),
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_menu_code UNIQUE (menu_code)
);
COMMENT ON TABLE permission_menu IS '平台菜单资源表，控制管理后台可见入口，不替代路由级安全边界';
COMMENT ON COLUMN permission_menu.menu_code IS '菜单稳定编码，用于角色菜单绑定';
COMMENT ON COLUMN permission_menu.parent_code IS '父菜单编码，用于构建多级菜单树';
COMMENT ON COLUMN permission_menu.path IS '前端路由或逻辑路径，后端以此对齐产品管理区域';
CREATE INDEX idx_permission_menu_parent_sort ON permission_menu (parent_code, sort_order);

CREATE TABLE permission_role_menu_binding (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    role_code VARCHAR(64) NOT NULL,
    menu_code VARCHAR(128) NOT NULL,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    binding_source VARCHAR(64) NOT NULL DEFAULT 'BOOTSTRAP',
    note VARCHAR(1000),
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_role_menu UNIQUE (tenant_id, role_code, menu_code),
    CONSTRAINT ck_permission_role_menu_tenant_non_negative CHECK (tenant_id >= 0)
);
COMMENT ON TABLE permission_role_menu_binding IS '角色菜单绑定表，表达某个租户下某个角色可以看到哪些后台入口';
COMMENT ON COLUMN permission_role_menu_binding.binding_source IS '绑定来源，例如 BOOTSTRAP、MANUAL、IMPORT、IDP_GROUP';
CREATE INDEX idx_permission_role_menu_role ON permission_role_menu_binding (tenant_id, role_code, enabled);

CREATE TABLE permission_route_policy (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    policy_name VARCHAR(128) NOT NULL,
    role_code VARCHAR(64) NOT NULL,
    http_method VARCHAR(16) NOT NULL DEFAULT 'ANY',
    path_pattern VARCHAR(256) NOT NULL,
    resource_type VARCHAR(64),
    action VARCHAR(64),
    effect VARCHAR(16) NOT NULL,
    priority INTEGER NOT NULL DEFAULT 100,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    description VARCHAR(1000),
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT ck_permission_route_tenant_non_negative CHECK (tenant_id >= 0),
    CONSTRAINT ck_permission_route_effect CHECK (effect IN ('ALLOW', 'DENY')),
    CONSTRAINT ck_permission_route_priority_non_negative CHECK (priority >= 0)
);
COMMENT ON TABLE permission_route_policy IS '路由权限策略表，供 gateway 和业务服务按角色、路径、资源类型、动作做授权判定';
COMMENT ON COLUMN permission_route_policy.resource_type IS '业务资源类型；为空表示路径级通配策略';
COMMENT ON COLUMN permission_route_policy.action IS '业务动作；为空表示动作级通配策略';
COMMENT ON COLUMN permission_route_policy.priority IS '策略优先级，数值越大越优先；同优先级 DENY 应优先于 ALLOW';
CREATE UNIQUE INDEX uk_permission_route_policy
    ON permission_route_policy (
        tenant_id,
        role_code,
        http_method,
        path_pattern,
        COALESCE(resource_type, ''),
        COALESCE(action, ''),
        effect
    );
CREATE INDEX idx_permission_route_role_priority
    ON permission_route_policy (tenant_id, role_code, enabled, priority);
CREATE INDEX idx_permission_route_semantic
    ON permission_route_policy (tenant_id, role_code, resource_type, action, enabled, priority);

CREATE TABLE permission_data_scope_policy (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    role_code VARCHAR(64) NOT NULL,
    resource_type VARCHAR(64) NOT NULL,
    scope_level VARCHAR(32) NOT NULL,
    scope_expression VARCHAR(1000),
    approval_required BOOLEAN NOT NULL DEFAULT FALSE,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    description VARCHAR(1000),
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_data_scope UNIQUE (tenant_id, role_code, resource_type),
    CONSTRAINT ck_permission_data_scope_tenant_non_negative CHECK (tenant_id >= 0),
    CONSTRAINT ck_permission_data_scope_level CHECK (scope_level IN ('SELF', 'PROJECT', 'TENANT', 'PLATFORM'))
);
COMMENT ON TABLE permission_data_scope_policy IS '数据范围权限策略表，定义不同角色能访问自己、项目、租户或平台范围内的数据';
COMMENT ON COLUMN permission_data_scope_policy.scope_expression IS '范围表达式模板，后续可演进为 JSON DSL';
COMMENT ON COLUMN permission_data_scope_policy.approval_required IS '该范围内操作是否仍需要审批，常用于跨租户、导出或敏感动作';
CREATE INDEX idx_permission_data_scope_role_resource
    ON permission_data_scope_policy (tenant_id, role_code, resource_type, enabled);

CREATE TABLE permission_project_membership (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    actor_id BIGINT NOT NULL,
    project_id BIGINT NOT NULL,
    workspace_id BIGINT,
    project_role VARCHAR(64) NOT NULL DEFAULT 'MEMBER',
    grant_source VARCHAR(64) NOT NULL DEFAULT 'MANUAL',
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_project_member UNIQUE (tenant_id, actor_id, project_id),
    CONSTRAINT ck_permission_project_member_tenant_non_negative CHECK (tenant_id >= 0)
);
COMMENT ON TABLE permission_project_membership IS '项目成员授权关系表，用于把 PROJECT 数据范围物化为 actor 可访问的 projectId 集合';
COMMENT ON COLUMN permission_project_membership.actor_id IS '操作者 ID，可对应用户、服务账号或外部身份映射';
COMMENT ON COLUMN permission_project_membership.grant_source IS '授权来源，例如 MANUAL、IMPORT、IDP_GROUP、APPROVAL';
CREATE INDEX idx_permission_project_actor_enabled
    ON permission_project_membership (tenant_id, actor_id, enabled, project_id);
CREATE INDEX idx_permission_project_project_role
    ON permission_project_membership (tenant_id, project_id, project_role, enabled);

CREATE TABLE permission_audit_record (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    trace_id VARCHAR(128),
    tenant_id BIGINT NOT NULL DEFAULT 0,
    actor_id BIGINT,
    actor_role VARCHAR(64),
    resource_type VARCHAR(64),
    resource_id VARCHAR(256),
    action VARCHAR(64) NOT NULL,
    result VARCHAR(32) NOT NULL,
    summary VARCHAR(1000) NOT NULL,
    detail_json TEXT,
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT ck_permission_audit_tenant_non_negative CHECK (tenant_id >= 0)
);
COMMENT ON TABLE permission_audit_record IS '权限审计记录表，保存授权判定、策略变更、outbox 人工处理等高风险操作证据';
COMMENT ON COLUMN permission_audit_record.detail_json IS '结构化审计详情，当前以 String/TEXT 保存，禁止存放密码、token 或原始敏感样本';
CREATE INDEX idx_permission_audit_tenant_time ON permission_audit_record (tenant_id, create_time);
CREATE INDEX idx_permission_audit_actor_time ON permission_audit_record (actor_id, create_time);
CREATE INDEX idx_permission_audit_resource_time ON permission_audit_record (resource_type, resource_id, create_time);
CREATE INDEX idx_permission_audit_trace ON permission_audit_record (trace_id);

CREATE TABLE permission_event_outbox (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    event_id VARCHAR(128) NOT NULL,
    event_type VARCHAR(128) NOT NULL,
    topic VARCHAR(255) NOT NULL,
    event_key VARCHAR(255),
    payload_json TEXT NOT NULL,
    status VARCHAR(32) NOT NULL DEFAULT 'PENDING',
    attempt_count INTEGER NOT NULL DEFAULT 0,
    max_attempts INTEGER NOT NULL DEFAULT 10,
    next_retry_time TIMESTAMP WITHOUT TIME ZONE,
    last_error VARCHAR(1000),
    sent_time TIMESTAMP WITHOUT TIME ZONE,
    tenant_id BIGINT NOT NULL DEFAULT 0,
    resource_type VARCHAR(64),
    resource_id VARCHAR(256),
    trace_id VARCHAR(128),
    create_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    update_time TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    CONSTRAINT uk_permission_event_outbox_event_id UNIQUE (event_id),
    CONSTRAINT ck_permission_event_outbox_status
        CHECK (status IN ('PENDING', 'SENDING', 'SENT', 'FAILED', 'DEAD', 'IGNORED')),
    CONSTRAINT ck_permission_event_outbox_attempts
        CHECK (attempt_count >= 0 AND max_attempts > 0 AND attempt_count <= max_attempts),
    CONSTRAINT ck_permission_event_outbox_tenant_non_negative CHECK (tenant_id >= 0)
);
COMMENT ON TABLE permission_event_outbox IS '权限事件 outbox 表，可靠暂存权限变更事件，支撑 gateway 缓存失效和人工补偿';
COMMENT ON COLUMN permission_event_outbox.event_id IS '业务事件 ID，消费者可用它做幂等';
COMMENT ON COLUMN permission_event_outbox.payload_json IS '事件载荷 JSON 文本；当前按 Java String 映射，未来可在 TypeHandler 就绪后迁移到 JSONB';
COMMENT ON COLUMN permission_event_outbox.status IS 'PENDING、SENDING、SENT、FAILED、DEAD、IGNORED 状态机';
CREATE INDEX idx_permission_event_outbox_dispatch
    ON permission_event_outbox (status, next_retry_time, create_time);
CREATE INDEX idx_permission_event_outbox_tenant_time
    ON permission_event_outbox (tenant_id, create_time);
CREATE INDEX idx_permission_event_outbox_resource
    ON permission_event_outbox (resource_type, resource_id);

